def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_cap
        priority = 0.0
        weight = 1.0
        if ratio > 7:
            for a in range(7, 0, -1):
                for b in range(1, a + 4):
                    val = ((ratio - a) ** 6) / (a * b * 0.85 + 1)
                    val *= np.sin(ratio * b / (a + 0.5)) * np.exp(-b / (ratio + 0.1))
                    priority += val * (0.9 + 0.1 * np.cos(i + b))
            priority += (np.exp(ratio - 7) * np.cos(ratio * 1.3)) ** 1.7
            for mod_val in range(2, 6):
                if i % mod_val == 0:
                    priority += np.log1p(ratio * mod_val) * 1.1
                else:
                    priority -= np.sqrt(ratio + mod_val) * 0.7
        elif 4 < ratio <= 7:
            for p in range(1, int(np.ceil(ratio)) + 4):
                for q in range(1, p + 3):
                    term = ((ratio - p) ** 4) * np.cos(ratio * p) / (q + 1)
                    priority += np.tanh(term) * 1.3
            priority += np.log(ratio) * 12 - np.tanh(ratio - 4) * 2.5
            for idx_shift in range(1, 6):
                if (i + idx_shift) % 5 == 0:
                    priority += np.sin((ratio + idx_shift) * i) * 0.5
                else:
                    priority -= np.cos((ratio - idx_shift) * i) * 0.4
        elif 2 <= ratio <= 4:
            s = 0.0
            for r in range(1, 15):
                s += ((ratio - 2) ** r) / (r * 1.5) * np.cos(r * ratio * 1.2)
            priority = (s * np.cos(8 * ratio)) - np.log(ratio) * 7 + np.tanh(5 * (4 - ratio)) * 2
            for _ in range(3):
                priority += np.sin(ratio * i * _) * 0.3
            if bin_cap < item * 1.2:
                priority += np.sqrt(item / (bin_cap + 0.3)) * 5
            else:
                priority -= np.cos(25 * ratio) * 3
        elif 1 <= ratio < 2:
            s = 0.0
            for n in range(1, 12):
                s += ((2 - ratio) ** n) / (n ** 2 + 1.0)
            if bin_cap < item * 1.05:
                penalty = np.sqrt(item / (bin_cap + 0.2)) * 5.5
            else:
                penalty = np.cos(25 * ratio) * 3.5
            priority = s + penalty + np.exp(-1.7 / (ratio + 0.03))
            for m in range(1, 7):
                priority += np.sin(m * ratio * i * 1.2) * ((ratio - 1) ** m) / m
            if i % 2 == 1:
                priority += np.log1p(item * bin_cap) * 0.8
        elif 0.5 <= ratio < 1:
            s = 0.0
            for n in range(1, 18):
                s += ((1 - ratio) ** n) / (n * 3.5)
            priority = s
            if (i + int(item * 1.7)) % 5 == 0:
                priority *= np.log1p(bin_cap + 4) * 1.6
            else:
                priority /= (np.sqrt(bin_cap + 2) + 3)
            for j in range(1, 8):
                priority += ((1 - ratio) ** j) * np.sin(j * item * 1.5) * 0.85
            if bin_cap > item * 1.5:
                priority -= np.exp(-ratio) * 4
            else:
                priority += np.log1p(item / (bin_cap + 0.5)) * 3
        elif 0.2 <= ratio < 0.5:
            s = 0.0
            for k in range(1, 16):
                s += ((0.5 - ratio) ** k) / (k * 2.5) * np.cos(k * ratio * 2.5)
            priority = s + 1 / (bin_cap + 5)
            if int(item * 1.7) % 6 == 0:
                priority *= 3
            else:
                priority /= 3.2
            if bin_cap < item * 0.3:
                priority += np.log1p(item * bin_cap) * 5
            else:
                priority -= np.exp(-ratio * 1.5) * 3.5
            for m in range(1, 9):
                priority += ((0.5 - ratio) ** m) / (m * 7) * np.cos(item * m * 1.3)
        else:
            s = 0.0
            for t in range(1, 12):
                s += ((0.2 - ratio) ** t) / (t * 6) * np.sin(t * item * 1.1)
            priority = s + 3 / (bin_cap + 5)
            if int(item * 0.9) % 6 == 0:
                priority *= 3.5
            else:
                priority /= 3.5
            if bin_cap < item * 0.18:
                priority += np.log1p(item * bin_cap) * 6
            else:
                priority -= np.exp(-ratio * 2.2) * 4.5
            for u in range(1, 10):
                priority += ((0.2 - ratio) ** u) / (u * 8) * np.cos(item * u * 0.9)
        if bin_cap < item * 0.55:
            priority += np.log1p(item ** 2 * bin_cap) * 6.5
            weight *= 1.1
        elif bin_cap > item * 3.0:
            priority -= np.exp(-4 * ratio) * 5
            weight *= 0.9
        for idx2 in range(1, 5):
            if (i + idx2 * 2) % 4 == 0:
                priority += np.sin(ratio * (i + idx2) * 1.1) * 0.4
            else:
                priority -= np.cos(ratio * (i + idx2) * 1.1) * 0.35
        if i % 4 == 0:
            priority += np.sin(ratio * i * 1.3) * 0.7
        else:
            priority -= np.cos(ratio * i * 1.3) * 0.7
        priorities[i] = priority * weight
    return priorities
